var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JANE_MASON_NULL_QM","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff...* *Huff...*","TWN":"呼呼……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"과자 먹을래?","JPN":"お菓子、食べる？","ENG":"Care for some crackers?","TWN":"要吃餅乾嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"막대 과자로.","JPN":"じゃあ、チョコスティックで。","ENG":"Cracker... Sticks.","TWN":"我要餅乾棒。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그거 달라고 할 줄 알았다. 하여간 막대 과자 진짜 좋아해.","JPN":"そういうと思った。本当にチョコスティックが大好物なんだね。","ENG":"I knew you’d say that. Gotta say, you really like cracker sticks.","TWN":"我就知道，你真的超愛餅乾棒的！"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그랬나?","JPN":"そうかな？","ENG":"Did I?","TWN":"是嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"학교 다닐 때도 수업 중에 몰래 먹다 걸려서 혼났잖아.","JPN":"学校に通ってた時も授業中にこっそり食べてたじゃん。先生にバレて怒られたし。","ENG":"When we were in school, you’d get scolded for trying to sneakily eat them during class.","TWN":"你不是還在上課中偷吃餅乾被抓到，結果被老師罵嗎！"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"선생님은 어떻게 알아챈 거지? 완전 범죄를 꿈꿨는데.","JPN":"先生はなんで気づいたんだろう？　完全犯罪を狙ってたつもりだったのに。","ENG":"How did the teacher know? It was the perfect crime.","TWN":"老師是怎麼發現的？我還以為我掩護得很好。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"입 주변이 과자 부스러기로 범벅이었으니까 그렇지.","JPN":"口の周りが食べかすだらけじゃ、そりゃバレるよ。","ENG":"Because your mouth was covered in crumbs, that’s why.","TWN":"應該是因為你嘴巴都是餅乾屑吧！"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Oh.","TWN":"啊，"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그러고 보니 네가 초코 묻은 부분만 한 입씩 뺏어 먹었었지.","JPN":"そういえば、アナタに一口ちょうだいと言われてチョコの部分だけ食べられた覚えがある。","ENG":"Thinking about it, you only took a bit from the parts covered in chocolate.","TWN":"你是不是把有巧克力的那邊吃掉了？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그때마다 기분이 굉장히…… 뜨거웠어.","JPN":"そのたびに気分がすごく……熱くなってた。","ENG":"Each time, it felt...hot.","TWN":"那時候我覺得……非常熱。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으응? 그거 무슨 기분인 건데?","JPN":"ううん？　それってどういう気分？","ENG":"Huh? What kind of feeling is that?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"뜨거웠다고. 쓰레기 소각장 불을 보는 느낌이랄까.","JPN":"熱かったよ。ゴミ焼却炉の火を見ている感じだった。","ENG":"It was hot like burning toxic waste.","TWN":"就是很熱，就很像是看到垃圾焚化爐的火一般？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"무슨 뜻인지는 잘 모르겠지만……","JPN":"どういう意味かわからないけど……","ENG":"I have no idea what that means...","TWN":"聽不太懂你想表達什麼……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어쨌든 디스플레이에 X자 뜬 거 보니까 기분 나빴단 거지?","JPN":"ディスプレイにXが出てきたってことは、つまり不快だったんだね？","ENG":"But whatever the case, seeing that your display shows an X, that means you felt bad, eh?","TWN":"不過顯示器上是顯示X，那應該就是很生氣的意思吧？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"진작 말을 하지. 전혀 몰랐어.","JPN":"嫌なら言ってくれればよかったのに。全然気づかなかった。","ENG":"You should have said so earlier. I had no idea.","TWN":"早說嘛～我又不知道！"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};